                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(document.getElementById('r1')){['r1','r2','r3'].forEach(id=>syncNum(id,'n'+id));cS();}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(document.getElementById('l1')){['l1','l2','l3'].forEach(id=>syncNum(id,'n'+id));cL();}
